insert into knowledge_nodes (id, project_id, node_key, label, category, sub_label, facts, talkpoint, description, sort_order) values
  ('3dcde88f-fc3b-5011-9f09-f7d8960d0d46','00000000-0000-0000-0000-00000000a001','gladia','Gladia by the Waters','project','GLADIA HEIGHT','[{"key":"Diện tích","value":"11.8 ha"},{"key":"Tổng vốn","value":"~VND 10,200 tỷ (~S$600M)"},{"key":"Liên doanh","value":"Keppel 49% × Khang Điền 51%"},{"key":"Vị trí","value":"Võ Chí Công, Bình Trưng Đông, TP Thủ Đức"},{"key":"Sản phẩm","value":"~200 căn thấp tầng + ~600 căn cao tầng"},{"key":"Chứng nhận","value":"BCA Green Mark for Districts (đầu tiên VN)"},{"key":"Trần","value":"~3.05m theo chuẩn Singapore"},{"key":"Mật độ XD","value":"chỉ 23.3–38% (thấp hơn nhiều thị trường)"}]'::jsonb,'"Gladia không chỉ là một dự án — đây là lần đầu tiên Singapore và Việt Nam cùng cấp chứng nhận khu đô thị cho cùng một địa chỉ. Khi Anh/Chị mua Gladia, Anh/Chị đang mua một tiêu chuẩn quy hoạch toàn cầu."','Gladia by the Waters là dự án hợp tác đầu tiên giữa Keppel (Singapore) và Khang Điền (Việt Nam) — vị trí 11.8 ha ba mặt giáp sông tại Bình Trưng Đông, TP Thủ Đức. Tổng giá trị phát triển ~VND 10,200 tỷ. Đây là dự án đầu tiên tại Việt Nam đạt chứng nhận BCA Green Mark for Districts từ Cục Xây dựng Singapore — vị thế độc nhất trên thị trường BĐS thấp tầng HCM, nơi 99% đối thủ chỉ có chứng nhận LOTUS Việt Nam hoặc không có chứng nhận nào. Sản phẩm đầu ra thị trường là thấp tầng, theo sau sẽ là phần cao tầng. Sản phẩm đầu tiên = nơi cả hai chủ đầu tư đặt cả uy tín thương hiệu.',0),
  ('3dc3fc74-a162-5f0f-87a9-161954c8c052','00000000-0000-0000-0000-00000000a001','keppel-land','Keppel Land','developer',null,'[{"key":"Vào Việt Nam","value":"1991 (>34 năm)"},{"key":"Dự án tại VN","value":"20+ dự án"},{"key":"Vốn đăng ký","value":"US$3.5 tỷ+"},{"key":"Nhân sự","value":"600+ (so với 8 năm 1991)"},{"key":"Pipeline","value":"~18,000 căn nhà"}]'::jsonb,'"Keppel đã ở Việt Nam 34 năm — họ đã chứng kiến mọi chu kỳ thị trường. Họ không đến rồi đi như nhiều nhà đầu tư ngoại khác."','Keppel Land là cánh tay phát triển BĐS của Keppel Ltd. — vào Việt Nam từ 1991 ngay sau Đổi Mới, là nhà đầu tư BĐS nước ngoài đầu tiên tại Việt Nam. Track record: Saigon Centre, The Estella, Estella Heights, Empire City, Riviera Point, Palm City, Celesta. Tỷ lệ hấp thụ >99% tại Empire City và Riviera Point. Năm 2022 đạt 12 giải tại PropertyGuru Vietnam Property Awards bao gồm "Best Sustainable Real Estate Developer" và "Best Mixed-use Developer".',1),
  ('58c1193c-245e-503c-b4d9-02d675092b21','00000000-0000-0000-0000-00000000a001','keppel-ltd','Keppel Ltd.','developer',null,'[{"key":"Thành lập","value":"1968 (Keppel Shipyard, Singapore)"},{"key":"Vốn hóa","value":"~US$17.24 tỷ (4/2026)"},{"key":"Mã CK","value":"SGX:BN4"},{"key":"Cổ đông lớn nhất","value":"Temasek 21.29%"},{"key":"Hoạt động","value":"20+ quốc gia"}]'::jsonb,'"Cổ đông lớn nhất của Keppel là Temasek — công ty đầu tư của Chính phủ Singapore. Khi Anh/Chị mua Gladia, Anh/Chị có sự đảm bảo gián tiếp của Chính phủ Singapore."','Keppel Ltd. là tập đoàn đa ngành Singapore, từ tên cũ "Keppel Corporation" đã chuyển sang mô hình asset-light theo Vision 2030. 4 mảng kinh doanh: Infrastructure (năng lượng, môi trường), Real Estate, Connectivity (data center, viễn thông), Corporate Activities. Top-10 công ty niêm yết tại Singapore. Cam kết net-zero 2050 đồng hành với cam kết COP26 của Việt Nam.',2),
  ('d5b6bff3-fa3a-512a-925e-d79d3b7588df','00000000-0000-0000-0000-00000000a001','temasek','Temasek Holdings','developer',null,'[{"key":"Loại","value":"Sovereign wealth fund"},{"key":"Sở hữu","value":"Chính phủ Singapore"},{"key":"Cổ phần tại Keppel","value":"21.29% (3/2025)"}]'::jsonb,'"Đây là điều khác biệt cốt lõi: Khi mua dự án của Keppel = mua một sản phẩm có nguồn vốn từ chính phủ Singapore."','Temasek là quỹ đầu tư quốc gia Singapore — sở hữu cổ phần đáng kể tại các tập đoàn lớn nhất Singapore bao gồm DBS, Singtel, Singapore Airlines, và Keppel. Sự hiện diện của Temasek tại Keppel mang lại kỷ luật tài chính, tiêu chuẩn quản trị toàn cầu và sự đảm bảo gián tiếp từ chính phủ Singapore.',3),
  ('b14f2673-525d-56e7-bb54-d773a64f01ca','00000000-0000-0000-0000-00000000a001','khang-dien','Khang Điền (KDH)','developer',null,'[{"key":"Thành lập","value":"2001, niêm yết HoSE 2010"},{"key":"Index","value":"VN30"},{"key":"Vốn hóa","value":"~VND 28,500 tỷ (5/2026)"},{"key":"Track record","value":"20,000+ căn đã giao"},{"key":"Tỷ lệ hấp thụ","value":"~100%"},{"key":"Đòn bẩy","value":"Debt/equity < 1.0"}]'::jsonb,'"Khang Điền là chủ đầu tư duy nhất Việt Nam giao sổ hồng cho khách trước khi mở bán dự án — đó không phải may mắn, đó là kỷ luật. Chủ tịch KDH (bà Mai Trần Thanh Trang) xuất thân ngành luật."','Khang Điền nổi tiếng với danh hiệu "ông hoàng sổ đỏ" — xây trước, bán sau, giao sổ hồng chỉ 3–6 tháng sau bàn giao. Tại Gladia, 67 sổ hồng đã được cấp ngày 7/11/2024 — TRƯỚC khi mở bán chính thức. Chuyên về biệt thự, nhà phố Đông và Nam HCM: Verosa Park, The Classia, Venica, Lucasta, Melosa, Jamila, Safira, The Privia. Hơn 50 dự án, 100% hấp thụ. Giải thưởng: "Developer of the Decade" tại PropertyGuru Vietnam Property Awards 2024; Vietnam National Brand 2022 & 2024; Top-10 Reputable Developer.',4),
  ('2230c263-ff5c-5141-bdba-5cb0992483cc','00000000-0000-0000-0000-00000000a001','kvf','Keppel Vietnam Fund','developer',null,'[{"key":"First close","value":"US$400M"},{"key":"Loại","value":"Real estate private fund"},{"key":"Cổ phần Gladia","value":"49% cùng Keppel Land"}]'::jsonb,'"Đây là cấu trúc tài chính cao cấp — vốn quỹ đầu tư private equity Singapore đang chảy vào dự án này."','Keppel Vietnam Fund (KVF) là quỹ BĐS tư nhân do Keppel quản lý, focus vào các cơ hội đầu tư BĐS chất lượng cao tại Việt Nam. First close US$400 triệu. KVF cùng Keppel Land sở hữu 49% trong liên doanh Gladia. Đây là cơ chế asset-light của Keppel theo Vision 2030.',5),
  ('d163bd02-eead-544c-8441-a12ebab96f82','00000000-0000-0000-0000-00000000a001','saigon-centre','Saigon Centre','comparable','Q1 — Keppel','[{"key":"Giai đoạn","value":"1996 (P1) & 2018 (P2)"},{"key":"Loại","value":"Mixed-use: Văn phòng + Takashimaya"},{"key":"Tenant nổi bật","value":"AIA, DBS, Mitsubishi, ANZ, Lazada, Lãnh sự Singapore"},{"key":"Occupancy","value":"100% năm"}]'::jsonb,'"Saigon Centre có Takashimaya. Đây là trung tâm thương mại Nhật mà các dự án khu Đông luôn nhắc đến như giấc mơ — và Gladia có Keppel làm chủ đầu tư, chính là chủ của Takashimaya."','Tòa nhà landmark CBD Sài Gòn của Keppel. Takashimaya mall đặt tại đây — một trong những mall cao cấp nhất Sài Gòn. Lãnh sự quán Singapore đặt trụ sở tại Saigon Centre — chứng minh độ tin cậy của tòa nhà.',6),
  ('bbce54ef-c4af-5dc8-94ef-36dd0cd8d039','00000000-0000-0000-0000-00000000a001','estella','The Estella','comparable','An Phú — 2012','[{"key":"Bàn giao","value":"2012"},{"key":"Số căn","value":"719"},{"key":"Hiện trạng","value":"Đã bán hết, đã giao"}]'::jsonb,'"Estella 2012 — Keppel đã giao đúng hẹn từ 14 năm trước. Đây là bằng chứng track record dài hạn."','Dự án Estella đầu tiên — bàn giao 2012, liên doanh Keppel + Tiến Phước. Là tiền đề cho Estella Heights (2018+).',7),
  ('6b9eec87-339c-5a2b-9618-0d69aa015d1f','00000000-0000-0000-0000-00000000a001','estella-heights','Estella Heights','comparable','An Phú — Keppel','[{"key":"Mở bán","value":"2/2015 @ VND 45 triệu/m²"},{"key":"Bàn giao P1","value":"Q4/2018"},{"key":"Bàn giao P2","value":"6/2019"},{"key":"Hiện tại","value":"VND 90–110 triệu/m²"},{"key":"Tăng giá","value":"~2× sau 11 năm"}]'::jsonb,'"Anh/Chị mua Estella Heights năm 2015 ở 45 triệu/m², hôm nay bán được 100 triệu/m² — gấp đôi sau 11 năm. Đó là track record của Keppel ngay tại Việt Nam."','Mở bán 2015 ở mức VND 45 triệu/m² (~US$2,000). Hiện tại thứ cấp VND 90–110 triệu/m² — tăng ~2× trong 11 năm. Estella Place mall (cùng dự án) đạt BCA Green Mark đầu tiên tại Việt Nam — 1/2015.',8),
  ('14264bdc-dd9c-5617-b109-26a84eb3d321','00000000-0000-0000-0000-00000000a001','empire-city','Empire City Thủ Thiêm','comparable','Thủ Thiêm — Keppel JV','[{"key":"Diện tích","value":"14.6 ha"},{"key":"Số căn","value":"3,787 căn cao cấp"},{"key":"Landmark","value":"Empire 88 — 88 tầng"},{"key":"Mở bán","value":"2017+"},{"key":"Hiện tại","value":"VND 125–200 triệu/m² (Cove cao hơn)"}]'::jsonb,'"Empire City đã giao và đang vận hành. Khi Anh/Chị mua Gladia, đây là chất lượng Anh/Chị sẽ nhận được."','Dự án landmark tại CBD mới Thủ Thiêm. Liên doanh Keppel + Tien Phuoc + Tran Thai + Gaw Capital. Bàn giao Linden/Tilia từ 2020. Tỷ lệ hấp thụ >99%. Tòa Empire 88 (88 tầng) là landmark cao thứ nhì Sài Gòn.',9),
  ('db2a84f5-38c4-5ea0-915e-986c6343e810','00000000-0000-0000-0000-00000000a001','riviera-point','Riviera Point','comparable','Q7 — Keppel','[{"key":"Hoàn thành","value":"2014+"},{"key":"Số căn","value":"~1,900"},{"key":"Hấp thụ","value":">93%"}]'::jsonb,'"Riviera Point ở Q7 — Keppel bán >93% trong thị trường khó. Đó là sức mạnh thương hiệu."','Dự án quy mô lớn tại Q7, liên doanh Keppel. Hấp thụ trên 93% tại thị trường khó.',10),
  ('758f1437-36be-55de-9e1a-67b31e98c6c9','00000000-0000-0000-0000-00000000a001','palm-city','Palm City','comparable','An Phú — ⚠ Keppel đã thoái vốn 2025','[{"key":"Loại","value":"30.2 ha waterfront, ~5,000 căn"},{"key":"Bàn giao P1","value":"2017"},{"key":"Bàn giao P2","value":"4/2019"},{"key":"⚠ Thoái vốn","value":"3/2025 — đổi thương hiệu Palm River"}]'::jsonb,'"Palm City đã được bàn giao đầy đủ và hoạt động tốt. Keppel thoái vốn không phải vì có vấn đề — mà vì chiến lược asset-light theo Vision 2030 của tập đoàn."','Lưu ý: Keppel đã thoái vốn Palm City vào 3/2025, lợi nhuận ròng ~S$55 triệu. Dự án được rebrand thành "Palm River" dưới Huong Viet Holdings. Đây là một phần chiến lược asset-light của Keppel — KHÔNG phải lỗi thực thi. Sales nên chuẩn bị trả lời khi khách hỏi.',11),
  ('9722efbb-65ee-57e6-b312-844059a00287','00000000-0000-0000-0000-00000000a001','celesta','Celesta Avenue / Heights','comparable','Nhà Bè — Keppel/Phú Long','[{"key":"Loại","value":"Cao tầng"},{"key":"Hoàn thành","value":"2019 (Heights/Rise)"},{"key":"Celesta Avenue","value":"Provisional BCA Green Mark 4/2024"}]'::jsonb,'"Celesta Avenue đạt BCA Green Mark — chứng minh đây là chính sách hệ thống của Keppel, không phải chỉ Gladia."','Liên doanh Keppel + Phú Long. Celesta Avenue đạt BCA Green Mark tạm thời 4/2024 — minh chứng Keppel áp dụng tiêu chuẩn Singapore cho nhiều dự án VN.',12),
  ('454308d0-e364-5112-8b5f-d6515ff57389','00000000-0000-0000-0000-00000000a001','saigon-sports-city','Saigon Sports City','comparable','An Phú — ⚠ Trễ tiến độ','[{"key":"Diện tích","value":"64 ha"},{"key":"Số căn","value":"3,000+"},{"key":"Vốn","value":"US$500M"},{"key":"Khởi công","value":"2/2019"},{"key":"⚠ Tiến độ","value":"Trễ — chỉ có nhà mẫu + cầu kết nối"},{"key":"Thoái vốn 70%","value":"2024–25"}]'::jsonb,'"Saigon Sports City là bài học Keppel đã học. Đó cũng là lý do Gladia là liên doanh với Khang Điền — chuyên gia pháp lý số 1 Việt Nam."','Cảnh báo: Đây là dự án Keppel trễ tiến độ rõ rệt. Sau 5 năm khởi công, mới chỉ xây nhà mẫu + cầu kết nối. Keppel thoái 70% vốn 2024-25 cho HTV Đại Phước (35%) và Vinobly (35%), giữ 30%. Thu hồi VND 7,130 tỷ (S$354M). Sales playbook: Khi khách đề cập, thừa nhận thẳng thắn. Khẳng định Gladia khác: Khang Điền pháp lý sạch, đã có sổ hồng, sản phẩm thấp tầng + cao tầng cụ thể, không phải township phức tạp.',13),
  ('a392d84c-df67-5237-8d92-ae565596a507','00000000-0000-0000-0000-00000000a001','verosa-park','Verosa Park','comparable','Q9 — Khang Điền','[{"key":"Loại","value":"Biệt thự nhà phố"},{"key":"Hiện trạng","value":"Đã giao, đầy đủ pháp lý"}]'::jsonb,'"Verosa Park là minh chứng KDH chuyên về thấp tầng — và Gladia là phiên bản cao cấp hơn của Verosa."','Một trong các dự án thấp tầng của Khang Điền tại Q9. Đại diện cho năng lực thấp tầng của KDH.',14),
  ('ab2b8213-bc22-5207-8c36-443fc5ba631b','00000000-0000-0000-0000-00000000a001','the-classia','The Classia','comparable','Q9 — Khang Điền','[{"key":"Loại","value":"Biệt thự"},{"key":"Hiện trạng","value":"Bàn giao"}]'::jsonb,null,'Dự án biệt thự cao cấp của KDH tại Q9 (cũ). Tiêu biểu cho hệ sinh thái thấp tầng chuẩn KDH.',15),
  ('c5168388-9b8e-5f15-8f07-78dae331a558','00000000-0000-0000-0000-00000000a001','the-privia','The Privia','comparable','Bình Tân — Khang Điền','[{"key":"Loại","value":"Cao tầng"}]'::jsonb,null,'Dự án cao tầng tiêu biểu KDH — cho thấy năng lực phát triển cao tầng song song với thấp tầng.',16),
  ('3188d74a-026c-55cf-842e-3e960774748c','00000000-0000-0000-0000-00000000a001','bca-singapore','BCA Singapore','cert',null,'[{"key":"Tên đầy đủ","value":"Building & Construction Authority"},{"key":"Thành lập","value":"1/4/1999"},{"key":"Cơ quan","value":"Bộ Phát triển Quốc gia Singapore"},{"key":"Giải thưởng","value":"Aspen Institute Energy Award 2010"}]'::jsonb,'"BCA là Bộ Xây dựng của Singapore. Khi Gladia được BCA cấp chứng nhận = chính phủ Singapore đã thẩm định và phê duyệt tiêu chuẩn của dự án."','BCA là cơ quan pháp luật của Singapore quản lý ngành xây dựng. Đặt tiêu chuẩn an toàn, chất lượng, bền vững. Năm 2010 là cơ quan chính phủ đầu tiên ngoài Bắc Mỹ nhận giải Aspen Institute về Năng lượng & Môi trường.',17),
  ('8baf102c-6698-5ce8-886c-d8cca2b15957','00000000-0000-0000-0000-00000000a001','green-mark','BCA Green Mark','cert',null,'[{"key":"Ra mắt","value":"1/2005"},{"key":"Áp dụng","value":"120+ dự án 10+ quốc gia"},{"key":"Bắt buộc tại SG","value":"Mọi tòa >2,000m² GFA"},{"key":"5 tiêu chí","value":"Năng lượng, Nước, Môi trường, Chất lượng nội thất, Đổi mới"}]'::jsonb,'"BCA Green Mark không phải nhãn hiệu marketing — đó là tiêu chuẩn bắt buộc tại Singapore. Có chứng nhận này = thuê cao hơn 12%."','Hệ thống chứng nhận xanh quốc gia Singapore, ra mắt 1/2005. Bắt buộc tại Singapore cho mọi tòa >2,000m². Đã áp dụng tại Trung Quốc, Malaysia, Việt Nam, Brunei, Ấn Độ, Thái Lan, Saudi Arabia, Indonesia, Philippines, Tanzania. Cushman & Wakefield (trích BCA): Tòa Green Mark CBD có giá thuê cao hơn tới 12%, occupancy cao hơn. Tòa Super Low Energy hoàn vốn đầu tư bền vững trong 5–6 năm.',18),
  ('a050d294-79b1-5e93-9a3b-403d6cbdb6a5','00000000-0000-0000-0000-00000000a001','green-mark-gold','Green Mark Gold','cert',null,'[{"key":"Điểm số","value":"75–84 / 100"},{"key":"Tiết kiệm năng lượng","value":"20–30%"},{"key":"Chi phí xây thêm","value":"+8–15%"},{"key":"Mức độ","value":"Chuẩn cho tòa Grade A Singapore"}]'::jsonb,null,'Green Mark Gold là một trong 4 hạng (Certified, Gold, GoldPlus, Platinum). Gold là chuẩn cho mọi tòa văn phòng Grade A tại Singapore. Tại Việt Nam, The Hallmark là tòa văn phòng đầu tiên đạt BCA Green Mark Gold.',19),
  ('5ed321a3-4d82-55c4-b78f-e8013af00e22','00000000-0000-0000-0000-00000000a001','green-mark-districts','Green Mark for Districts','cert',null,'[{"key":"Loại","value":"Chứng nhận cấp khu đô thị"},{"key":"Phạm vi","value":"Quy hoạch toàn khu, không chỉ tòa nhà"},{"key":"Tại Việt Nam","value":"⭐ Gladia là dự án ĐẦU TIÊN"}]'::jsonb,'"Đây là vũ khí định vị thương hiệu mạnh nhất. Gladia là dự án ĐẦU TIÊN tại VN đạt Green Mark for Districts. Không có đối thủ nào có chứng nhận cấp khu đô thị từ Singapore."','Đây là hạng chứng nhận đặc biệt cho cả khu đô thị — không phải chỉ một tòa nhà. Đánh giá: quy hoạch giao thông, sử dụng năng lượng cấp khu, quản lý nước, vật liệu, môi trường. Gladia by the Waters là dự án ĐẦU TIÊN tại Việt Nam đạt chứng nhận này.',20),
  ('b2df30b0-b5bd-5b78-bd6b-b1ad42423e06','00000000-0000-0000-0000-00000000a001','lotus-vn','LOTUS (VGBC)','cert',null,'[{"key":"Ra mắt","value":"2010 — Vietnam Green Building Council"},{"key":"Số dự án đạt","value":"63 dự án tại VN (4/2024)"}]'::jsonb,'"Đối thủ chỉ có LOTUS — chứng nhận trong nước. Gladia có cả LOTUS + BCA Green Mark for Districts từ Singapore."','Hệ thống chứng nhận xanh của Việt Nam. Phù hợp khí hậu, vật liệu và quy định VN. Là chuẩn phổ biến trong nước, nhưng không có sự công nhận quốc tế như BCA Green Mark.',21),
  ('3ba4e9a8-a3a9-50b2-8654-1f7ee455e050','00000000-0000-0000-0000-00000000a001','leed','LEED (USGBC)','cert',null,'[{"key":"Ra mắt","value":"1998 — USGBC"},{"key":"4 hạng","value":"Certified → Platinum"}]'::jsonb,null,'Hệ thống chứng nhận xanh của Mỹ — phổ biến toàn cầu. Tương đương BCA Green Mark về uy tín quốc tế.',22),
  ('f3cacc81-305e-5128-a32f-dcbfb757beae','00000000-0000-0000-0000-00000000a001','metro-1','Metro Line 1','metro','Bến Thành – Suối Tiên','[{"key":"Khai trương","value":"22/12/2024"},{"key":"Chiều dài","value":"19.7 km, 14 trạm"},{"key":"Tàu","value":"17 đoàn tàu Hitachi"},{"key":"Tốc độ","value":"110 km/h trên cao, 80 km/h ngầm"},{"key":"Tác động giá","value":"+15–20% YoY các vùng quanh trạm"}]'::jsonb,'"Metro 1 đã làm điều này cho Thảo Điền. Metro 6 sẽ làm điều tương tự cho Phú Hữu."','Khai trương 22/12/2024 — tài trợ JICA. 14 trạm: 3 ngầm (Bến Thành, Nhà hát, Ba Son) + 11 trên cao. Tác động giá BĐS: Savills Q3/2025 — "khu Đông tăng 15-20% YoY." CBRE — "tại các trạm dọc tuyến giá tăng 50-200%." Thảo Điền hiện ở mức US$3,933-7,000+/m². Đề xuất mở rộng 41.4 km tới Đồng Nai + Long Thành — VND 60,261 tỷ đã được phê duyệt.',23),
  ('51435925-cc2a-5a00-9c30-4b01d388138f','00000000-0000-0000-0000-00000000a001','metro-2','Metro Line 2','metro','Bến Thành – Tham Lương','[{"key":"Khởi công","value":"15/1/2026"}]'::jsonb,'"Metro 6 sẽ giao Metro 2 tại Bà Quẹo. Khách Gladia có thể đi tàu thẳng đến Bến Thành không phải đổi tuyến nhiều."','Metro 2 đã chính thức khởi công 15/1/2026. Kết nối quận 1, 3, 10, 12, Tân Bình — phần kết nối với Metro 6 tại trạm Bà Quẹo.',24),
  ('2e80db57-0974-50f3-a33a-9d2b18498397','00000000-0000-0000-0000-00000000a001','metro-6','Metro Line 6 — GLADIA LINE','metro','Tân Sơn Nhất – Phú Hữu','[{"key":"Tổng","value":"53.8 km, 38 trạm"},{"key":"Phase 1","value":"Tân Sơn Nhất → Phú Hữu"},{"key":"Khởi công","value":"2026"},{"key":"Hoàn thành","value":"2030"},{"key":"Trạm cuối","value":"Phú Hữu (cạnh Gladia)"}]'::jsonb,'"Khi Long Thành mở cửa, Tân Sơn Nhất quá tải, chính phủ KHÔNG có lựa chọn nào khác ngoài Metro 6. US$16 tỷ đầu tư cho sân bay sẽ bỏ ngỏ nếu không có metro."','Tuyến metro chiến lược cho Gladia. Phase 1 ưu tiên 2026-2030: Tân Sơn Nhất → Phạm Văn Đồng → Phú Hữu. Giao cắt với Metro 2 (Bà Quẹo) và đường sắt Thủ Thiêm-Long Thành tại trạm Phú Hữu — nghĩa là một hành trình: Lên Metro 6 ở Phú Hữu, đổi sang express rail ở Phú Hữu/Thủ Thiêm, đến Long Thành. Một dịch vụ express 30 phút Tân Sơn Nhất → Long Thành đang nghiên cứu, đi qua Metro 6 + đường sắt TT-LT.',25),
  ('c07de8cc-f47d-52ee-b73f-6bd275616909','00000000-0000-0000-0000-00000000a001','thu-thiem-long-thanh','Thủ Thiêm – Long Thành Rail','metro',null,'[{"key":"Chiều dài","value":"42 km, 20 trạm"},{"key":"Vốn","value":"VND 84,753 tỷ (US$3.2B)"},{"key":"Tốc độ","value":"120 km/h"},{"key":"Nhà đầu tư","value":"PPP — Thaco"},{"key":"Khởi công","value":"Cuối 2026"},{"key":"Vận hành","value":"2030"}]'::jsonb,null,'Đường sắt express kết nối Thủ Thiêm với Long Thành Airport. 42 km, 20 trạm, tốc độ thiết kế 120 km/h. Giao cắt Metro 6 tại Phú Hữu/Thủ Thiêm — tạo thành mạng kết nối Tân Sơn Nhất – Phú Hữu – Long Thành.',26),
  ('1f8d30da-fd93-57fa-966e-e64499aa44d9','00000000-0000-0000-0000-00000000a001','ring-road-2','Vành đai 2','road','Vành đai nội đô tương lai','[{"key":"Tổng","value":"~64 km"},{"key":"Đã vận hành","value":"50 km (gồm Võ Chí Công)"},{"key":"Còn lại","value":"14 km — 4 đoạn"},{"key":"Đoạn Phú Hữu","value":"3.6 km, VND 9,800+ tỷ"},{"key":"Hoàn thành","value":"~2027–2029"}]'::jsonb,'"Khi Vành đai 2 hoàn thành ~2027-2029, BĐS trong vành đai sẽ được định giá là NỘI ĐÔ, không còn là VEN ĐÔ. Gladia chính là trong vành đai đó."','Vành đai 2 sẽ trở thành vành đai nội đô khi hoàn thiện ~2027-2029. Gladia nằm trong Vành đai 2. Đoạn Phạm Văn Đồng – Gò Dưa đã tái khởi công, mục tiêu hoàn thành 30/4/2027.',27),
  ('570e76d0-fbb9-5cf8-a877-e3cdb1681822','00000000-0000-0000-0000-00000000a001','ring-road-3','Vành đai 3','road','Vành đai kinh tế — Bùng nổ 6/2026','[{"key":"Tổng","value":"76.34 km"},{"key":"Vốn","value":"VND 75,378 tỷ (~US$3B)"},{"key":"Đoạn cao tốc","value":"8 làn, 100 km/h"},{"key":"Đoạn cao TP.HCM","value":"15 km — kỹ thuật 12/2025"},{"key":"Mở cửa","value":"30/4/2026"},{"key":"HOÀN THÀNH","value":"30/6/2026"},{"key":"Đi qua","value":"TP.HCM, Đồng Nai, Tây Ninh"}]'::jsonb,'"Vành đai 3 hoàn thành tháng 6 năm nay (2026). Đây là vành đai kinh tế — sẽ làm cho Phú Hữu trở thành cửa ngõ logistic phía Nam."','Cao tốc 8 làn, tốc độ thiết kế 100 km/h. Phần đi qua TP Thủ Đức 15 km — đã thông kỹ thuật 12/2025, mở cửa trước 30/4/2026. Toàn tuyến hoàn thành 30/6/2026. Kết nối 5 cao tốc tỏa: HCMC–Trung Lương, HCMC–Long Thành–Dầu Giây, Bến Lức–Long Thành, HCMC–Mộc Bài, HCMC–Chơn Thành. Vinhomes Grand Park đã ghi nhận tăng tốc thị trường trực tiếp từ Vành đai 3.',28),
  ('455f0bec-e3e1-5ba9-acd2-36166d3be6fc','00000000-0000-0000-0000-00000000a001','ring-road-4','Vành đai 4','road','Vành đai công nghiệp','[{"key":"Tổng","value":"~159 km"},{"key":"Vốn Phase 1","value":"~VND 120,000 tỷ"},{"key":"Khởi công","value":"Q2/2026"},{"key":"Hoàn thành dự kiến","value":"~2031"},{"key":"Mô hình","value":"PPP"},{"key":"Tốc độ","value":"4 làn → mở rộng, 100 km/h"}]'::jsonb,'"Vành đai 4 chỉ dành cho công nghiệp — nghĩa là Vành đai 2 (Gladia) chỉ dành cho dân cư và thương mại cao cấp. Phân vùng rõ ràng."','Vành đai công nghiệp kết nối Cái Mép-Thị Vải, Long Thành Airport, Biên Hòa, Bình Dương — chuyển hướng vận tải hàng hóa ra khỏi nội đô.',29),
  ('a685ea87-40f2-5267-b4e4-88e66941ed1b','00000000-0000-0000-0000-00000000a001','vo-chi-cong','Võ Chí Công','road','Mặt tiền Gladia','[{"key":"Hiện tại","value":"Một phần Vành đai 2"},{"key":"Đường liên cảng","value":"5.9 km, 60m rộng, 12 làn"},{"key":"Vốn","value":"~VND 9,000 tỷ"},{"key":"Trình duyệt","value":"24/12/2025"}]'::jsonb,'"60 mét. Lớn hơn gấp đôi đường mặt tiền dự án đối thủ. Đây không phải số trừu tượng — đây là thực tế giao thông tương lai."','Mặt tiền trực tiếp của Gladia. Hiện là một phần Vành đai 2. Đường liên cảng Cát Lái – Phú Hữu đã trình duyệt 24/12/2025: 5.9 km, mặt cắt 60m, 12 làn, tốc độ thiết kế 60 km/h, vốn ~VND 9,000 tỷ. Có cầu vượt cao 4 làn từ cảng Phú Hữu đến SP-ITC, 6 làn đến nút HLD; cầu Ba Cua mới 10 làn. Hiệu ứng: Container/xe tải sẽ đi qua "làn xanh" trên cao — bỏ khỏi Nguyễn Thị Định / Nguyễn Duy Trinh / Võ Chí Công mặt đất. Nâng cao chất lượng sống cho cư dân Gladia.',30),
  ('b27cb50a-723f-5628-9adb-7ad3d2b03059','00000000-0000-0000-0000-00000000a001','my-thuy','Nút giao Mỹ Thủy 4 tầng','road','Cách Gladia ~2 km','[{"key":"Vốn","value":"VND 3,622 tỷ"},{"key":"Loại","value":"4 tầng — đầu tiên VN"},{"key":"Kết nối","value":"Nguyễn Thị Định + Đồng Văn Cống + Võ Chí Công"},{"key":"Hoàn thành","value":"Q3/2026 (trễ từ 4/2026)"}]'::jsonb,'"Mỹ Thủy 4 tầng — đầu tiên Việt Nam. Q3 năm nay xong. Đây là dự án xử lý kẹt xe ngay cửa ngõ Gladia."','Nút giao 4 tầng đầu tiên Việt Nam: hầm chui + mặt đất + cầu vượt + ramps. Cửa ngõ vào Cát Lái Port (cảng container lớn nhất VN). Tách container khỏi giao thông đô thị — cùng tác dụng nâng cao chất lượng sống cho Gladia.',31),
  ('d17a00dc-281c-59dc-961a-f2f39d6a77d4','00000000-0000-0000-0000-00000000a001','cat-lai-bridge','Cầu Cát Lái','road','HCMC ↔ Đồng Nai','[{"key":"Khởi công","value":"15/1/2026"},{"key":"Vốn (cùng Phú Mỹ 2)","value":"VND 40,000+ tỷ"},{"key":"Riêng Cát Lái","value":"~VND 20,614 tỷ (~US$830M)"},{"key":"Chiều dài","value":"11.6 km, cầu dây văng"},{"key":"Hoàn thành","value":"2028–2029"}]'::jsonb,'"Cầu Cát Lái đã khởi công năm nay. 2028-2029 hoàn thành. Khi đó Gladia là cửa ngõ HCMC sang Đồng Nai — không phải vùng ven."','Cầu dây văng thay thế phà Cát Lái quá tải. Đã khởi công 15/1/2026. Bắt đầu từ Nguyễn Thị Định, cách Mỹ Thủy 400m; kết thúc tại cao tốc Bến Lức – Long Thành ở xã Đại Phước, Đồng Nai. Xây 4 năm → 2028-2029. 3 tác động: (1) Kết nối thẳng Long Thành Airport qua cao tốc BL-LT, (2) Container đi qua cầu + đường liên cảng, (3) Phú Hữu thành cửa ngõ HCMC ↔ Đồng Nai.',32),
  ('5cb6d239-8f6a-5ee6-be07-2e1694cb5ddd','00000000-0000-0000-0000-00000000a001','an-phu-interchange','Nút giao An Phú','road',null,'[{"key":"Vốn","value":"VND 3,400+ tỷ"},{"key":"Loại","value":"3 tầng"},{"key":"Hoàn thành","value":"Q2/2026"},{"key":"Đường hầm HC1-02","value":"Đã mở"}]'::jsonb,null,'Nút giao 3 tầng kết nối Mai Chí Thọ với cao tốc HCMC – Long Thành – Dầu Giây. Q2/2026 hoàn thành.',33),
  ('1dd8dcf7-8509-5528-9e4a-7b04a753ec7d','00000000-0000-0000-0000-00000000a001','inter-port-road','Đường liên cảng Cát Lái – Phú Hữu','road',null,'[{"key":"Chiều dài","value":"5.9 km"},{"key":"Rộng","value":"60m, 12 làn"},{"key":"Vốn","value":"~VND 9,000 tỷ"}]'::jsonb,null,'Đường chuyên cho vận tải cảng — chuyển hướng container/xe tải khỏi đường dân sinh. Trình duyệt 24/12/2025.',34),
  ('60d51813-8d63-52e2-8e65-b8bc04c8dd98','00000000-0000-0000-0000-00000000a001','long-thanh','Sân bay Long Thành','amenity','Quốc tế — 2026','[{"key":"Tổng vốn","value":"~US$16 tỷ (program)"},{"key":"Cách Gladia","value":"~40 km / 20 phút cao tốc"},{"key":"Diện tích","value":"5,000 ha"},{"key":"Phase 1","value":"25 triệu pax/năm"},{"key":"Phase 1 hoàn thành","value":"72% (3/2026)"},{"key":"Khai trương TM","value":"Q4/2026"},{"key":"Phase 3 (2050)","value":"100 triệu pax — lớn nhất ĐNÁ"}]'::jsonb,'"Long Thành chính thức mở cửa Q4 năm nay. Trong 6 tháng tới, 14,000 chuyên gia + lao động cao cấp sẽ tới Đồng Nai — họ thuê nhà ở đâu? Gladia."','Tổng vốn ~US$16 tỷ (LƯU Ý: con số đúng — không phải $36 tỷ như đôi khi nghe nói). 3/2026 phase 1 đã hoàn thành 72%. Runway 1 đã xong 4/2025 (sớm 3 tháng). Chuyến bay kỹ thuật đầu 12/2025. Khai trương thương mại Q4/2026. 80% chuyến quốc tế HCM sẽ chuyển sang Long Thành. 14,000 việc làm cần lấp đến cuối 2026 — ACV đã bắt đầu tuyển từ 4/2026. Phase 3 đến 2050: 100 triệu hành khách/năm — sân bay lớn nhất Đông Nam Á, ngang Bangkok Suvarnabhumi và Singapore Changi.',35),
  ('5d67986f-ff80-54c5-9682-03e7a578baae','00000000-0000-0000-0000-00000000a001','tan-son-nhat','Tân Sơn Nhất Airport','amenity',null,'[{"key":"Hiện tại","value":"Quá tải nghiêm trọng"},{"key":"Sau Long Thành","value":"20% chuyến quốc tế giữ lại"}]'::jsonb,null,'Sân bay hiện hữu — quá tải. Sau khi Long Thành mở cửa, 80% quốc tế chuyển sang Long Thành, 20% còn lại + nội địa giữ tại Tân Sơn Nhất. Metro 6 kết nối Tân Sơn Nhất → Phú Hữu = Gladia có quyền truy cập rapid transit đến cả hai sân bay.',36),
  ('4bc28cdc-b3c3-5304-a440-aff7f66a0364','00000000-0000-0000-0000-00000000a001','shtp','Saigon Hi-Tech Park (SHTP)','amenity','Cách Gladia 5–8 km','[{"key":"Diện tích","value":"913 ha (P1: 300, P2: 613)"},{"key":"Số nhân sự","value":"~25,000+ chuyên gia"},{"key":"Vốn tích lũy","value":"US$7.1 tỷ+"},{"key":"Xuất khẩu tích lũy","value":"US$45 tỷ+"},{"key":"% xuất khẩu HCM hi-tech","value":"94%"}]'::jsonb,'"25,000 chuyên gia SHTP — đó là 25,000 hợp đồng thuê tiềm năng ngay cạnh Gladia. Họ muốn ở đâu? An toàn, xanh, mật độ thấp. Đó chính là Gladia."','Tenant lớn: Intel (nhà máy chip lớn nhất thế giới, $1B+); Samsung Electronics HCMC Complex (SEHC) $2B; Nidec Nhật $500M kế hoạch 20,000 công nhân; Sanofi Pháp; Sonion Đan Mạch 2,000 công nhân; Datalogic, Microchip, FPT, Nanogen. Mức lương: Kỹ sư cao cấp + quản lý cấp trung Intel/Samsung/Nidec: US$1,500-4,000+/tháng — tệp thuê uy tín ngay cạnh Gladia. Tầm nhìn 2030: trung tâm khoa học công nghệ quốc tế. 2045: hi-tech park net-zero đầu tiên Việt Nam.',37),
  ('5396ba6f-4a9d-5d6d-878d-b14eb28c45d9','00000000-0000-0000-0000-00000000a001','cai-mep','Cảng Cái Mép – Thị Vải','amenity',null,'[{"key":"Đặc điểm","value":"Cảng nước sâu DUY NHẤT VN"},{"key":"Tuyến đến Mỹ/EU","value":"Trực tiếp (chỉ sau Singapore/Malaysia ĐNÁ)"},{"key":"Throughput 2024","value":"6.5 triệu TEU (+33% YoY)"},{"key":"Tăng trưởng 9T/2025","value":"+18% YoY"}]'::jsonb,'"Gladia nằm trên trục logistics HCMC port → Cái Mép. Khi xuất khẩu tăng = nhu cầu chuyên gia tại HCM tăng = nhu cầu nhà ở cao cấp tăng."','Cảng nước sâu duy nhất VN có dịch vụ trực tiếp tới Mỹ/EU. 22 bến hoạt động, 117.8 triệu tấn/năm. 2024: 6.5 triệu TEU (+33% YoY). 9 tháng/2025: +18% YoY (VPA). Cai Mep Ha Logistics Center: 1,763 ha quy hoạch bao gồm free-trade zone.',38),
  ('5d2c743a-b05c-5c24-b897-9ad43150b13e','00000000-0000-0000-0000-00000000a001','cat-lai-port','Cảng Cát Lái','amenity',null,'[{"key":"Đặc điểm","value":"Cảng container lớn nhất VN"},{"key":"Kết nối Gladia","value":"Qua Mỹ Thủy + đường liên cảng"}]'::jsonb,null,'Cảng container lớn nhất Việt Nam. Khách logistics doanh nhân — segment target chính của Gladia.',39),
  ('8a00c0b3-f34d-5578-a6e6-e5f896ceab61','00000000-0000-0000-0000-00000000a001','aih-hospital','Bệnh viện Quốc tế','amenity','⚠ Cần xác minh','[{"key":"Trạng thái","value":"⚠ Chưa xác minh được"},{"key":"BV gần nhất xác nhận","value":"AIH, Vinmec Central Park, FV"}]'::jsonb,'"Tham chiếu BV Quốc tế Phú Hữu cần xác minh. Hiện tại trong khu vực: AIH Q2, Vinmec Q2, FV — đều là tiêu chuẩn quốc tế."','Lưu ý: Tham chiếu "Bệnh viện Quốc tế Phú Hữu 2028" chưa thể xác minh trong nguồn công khai. Có thể là tiện ích trong masterplan Palm City cũ, hoặc dự án chưa công bố, hoặc định vị marketing. BV gần được xác nhận: American International Hospital (Q2), Vinmec Central Park (Q2), FV Hospital, Hạnh Phúc International (tại Estella Place). Sales: Xác minh với phòng KD Khang Điền trước khi dùng trong tài liệu khách hàng.',40),
  ('31827077-73ea-50c1-b530-0722f2c48e5f','00000000-0000-0000-0000-00000000a001','thu-duc-city','TP Thủ Đức','location',null,'[{"key":"Thành lập","value":"12/2020"},{"key":"Diện tích","value":"211.56 km²"},{"key":"Dân số 2030","value":"1.8M → 2.6M (2040) → 3M"},{"key":"Masterplan duyệt","value":"21/1/2025"},{"key":"Gọi vốn","value":"535 dự án ~US$31.6 tỷ"}]'::jsonb,'"TP Thủ Đức = TP đầu tiên trong TP của VN. Định vị là innovation hub. Gladia ở trung tâm masterplan này."','Thành phố ĐẦU TIÊN trong thành phố tại Việt Nam — gộp Q2 + Q9 + Thủ Đức cũ. 9 phân vùng phát triển / 11 khu chiến lược. Trong đó: Bình Trưng Tây (Gladia) = cầu nối giữa Thủ Thiêm CBD và khu logistic cảng. Mục tiêu giao thông công cộng đáp ứng 50-60% nhu cầu đi lại đến 2040.',41),
  ('f3ef550d-31ac-5400-8dd7-b87309c9da98','00000000-0000-0000-0000-00000000a001','phu-huu','Phú Hữu Ward','location',null,'[{"key":"Khu vực","value":"Q9 cũ (nay TP Thủ Đức)"},{"key":"Giá hiện tại","value":"VND 28-150 triệu/m² tùy mặt tiền"}]'::jsonb,'"Phú Hữu đang ở chân chu kỳ tăng giá — Diamond Island, Estella đều bắt đầu từ chân tương tự năm 2014-2015."','Phường Phú Hữu — khu vực hiện tại đang ở giai đoạn đầu chu kỳ tăng giá. Bao gồm cảng Phú Hữu, một phần trục Võ Chí Công. Giá tham khảo 2025: nội bộ Gò Cát/Bưng Ông Thoàn: VND 28-50 triệu/m²; mặt tiền Nguyễn Duy Trinh: VND 50-150 triệu/m²; mặt tiền Liên Phường (cạnh Vinhomes GP): tới ~VND 95 triệu/m².',42),
  ('ae73b1d8-3f7a-5f35-bcac-b03c07810160','00000000-0000-0000-0000-00000000a001','binh-trung-dong','Bình Trưng Đông','location',null,'[{"key":"Khu vực","value":"Q2 cũ, nay TP Thủ Đức"},{"key":"Vị trí Gladia","value":"Mặt tiền Võ Chí Công"}]'::jsonb,null,'Địa chỉ thực tế của Gladia. Nằm trong khu quy hoạch Cát Lái – Bình Trưng Đông 66.08 ha. Khoảng cách: 3 phút Thủ Thiêm, 10 phút Phú Mỹ Hưng, 20 phút Bến Thành, 20 phút Long Thành cao tốc.',43),
  ('c51558f3-0885-5a97-8d2c-65228554b7d5','00000000-0000-0000-0000-00000000a001','thu-thiem','Thủ Thiêm','location',null,'[{"key":"Vai trò","value":"CBD tài chính mới của HCM"}]'::jsonb,null,'Trung tâm tài chính mới của HCM — Empire City (Keppel) là dự án landmark tại đây. Cách Gladia 3 phút qua cầu Thời Đại.',44),
  ('d632342e-7b2f-54f1-b36b-5545e6ecf3ba','00000000-0000-0000-0000-00000000a001','thao-dien','Thảo Điền','location',null,'[{"key":"Giá hiện tại","value":"US$3,933-7,000+/m²"},{"key":"Sau Metro 1","value":"+50 đến +200%"}]'::jsonb,'"Thảo Điền hôm nay là Phú Hữu năm 2030. Cùng pattern: trạm metro, expat community, chuẩn quốc tế."','Khu expat truyền thống. Sau Metro 1, giá tăng 50-200% các vùng dọc tuyến. Là bài học cho Phú Hữu sau Metro 6.',45),
  ('c284a55c-690f-519b-907c-711662abe3e4','00000000-0000-0000-0000-00000000a001','an-phu','An Phú','location',null,'[{"key":"Vai trò","value":"Khu cao cấp Q2 cũ"},{"key":"Dự án landmark","value":"Estella Heights (Keppel), Palm City"}]'::jsonb,null,'Khu cao cấp gần CBD — nơi Estella Heights và Palm City đặt nền móng cho thương hiệu Keppel tại VN.',46),
  ('3a35c8fe-8e16-59ef-969c-2da4e5c3b62e','00000000-0000-0000-0000-00000000a001','diamond-island','Đảo Kim Cương','comparable','Q2 — Kusto Home','[{"key":"Mở bán","value":"~2014-2016 (P2)"},{"key":"Giá launch","value":"US$1,800-2,200/m² (VND 40-50tr/m²)"},{"key":"Hiện tại","value":"VND 90-120 triệu/m²"},{"key":"Tăng","value":"~2.0-2.5× trong 10 năm"}]'::jsonb,'"Anh/Chị nhớ Đảo Kim Cương năm 2015? Ai cũng nói xa, đường khó. Mua 40-50tr/m², giờ 100-120tr/m². Phú Hữu hôm nay = Đảo Kim Cương năm 2015."','Bài học vàng: Mở bán giai đoạn 2 ở mức VND 40-50 triệu/m². Hôm nay VND 90-120 triệu/m². Tăng 2.0-2.5× trong 10 năm.',47),
  ('7b90ce58-c6ed-5ee6-80fc-ab6985db141a','00000000-0000-0000-0000-00000000a001','vista-verde','Vista Verde','comparable','Q2 — CapitaLand','[{"key":"Mở bán","value":"7/2014"},{"key":"Giá launch","value":"US$1,500-2,000/m²"},{"key":"Hiện tại","value":"VND 54-87 triệu/m²"},{"key":"Tăng","value":"~2×+ trong 10 năm"}]'::jsonb,null,'Một case study tăng giá quan trọng. Mở bán 2014, hiện tại trung bình ~VND 66 triệu/m² (8/2022).',48),
  ('8774ce3c-2407-58a6-87e0-8a7e0f2ea485','00000000-0000-0000-0000-00000000a001','masteri-thao-dien','Masteri Thảo Điền','comparable',null,'[{"key":"Mở bán","value":"2014 @ VND 35tr/m²"},{"key":"Hiện tại","value":"VND 60-100+ tr/m²"},{"key":"Tăng","value":"~2-3×"}]'::jsonb,null,'Mở bán 2014 ở mức 35tr/m². Sau khi Metro 1 hoàn thành — giá lên 60-100+ triệu/m². Tăng 2-3 lần trong 10-11 năm.',49),
  ('7cf6ade3-ea8a-533d-bb2e-c672d07ccc61','00000000-0000-0000-0000-00000000a001','vinhomes-gp','Vinhomes Grand Park','comparable','Q9 — Floor Reference','[{"key":"Mở bán","value":"2019 (Sapphire) @ VND 30-35tr/m²"},{"key":"Origami","value":"VND 34tr/m²"},{"key":"Căn hộ hiện tại","value":"VND 50-80tr/m²"},{"key":"Villa","value":"US$740K (150m²) — US$1.5M (302m²)"},{"key":"Tăng","value":"~1.5-2× trong 5-6 năm"}]'::jsonb,null,'Tham chiếu giá sàn dưới Gladia. Gladia định giá CAO HƠN Vinhomes GP nhưng THẤP HƠN An Phú/Thảo Điền hiện tại — kịch bản upside là hội tụ với An Phú trong 5-7 năm.',50),
  ('89b74583-594a-509e-b048-484a62e14dc0','00000000-0000-0000-0000-00000000a001','thanh-my-loi','Thạnh Mỹ Lợi','comparable','Q2 — Câu chuyện vàng','[{"key":"Đất biệt thự 2015","value":"~VND 50-80tr/m²"},{"key":"Hiện tại (nội bộ)","value":"VND 100-180tr/m²"},{"key":"Hiện tại (mặt sông)","value":"tới VND 400tr/m²"},{"key":"Tăng","value":"3-5× trong 10 năm"}]'::jsonb,'"Thạnh Mỹ Lợi là bài học mạnh nhất. Cùng câu chuyện kẹt xe, cùng câu chuyện hạ tầng. Ai mua năm 2015, hôm nay thắng lớn."','Bài học mạnh nhất. Năm 2015 ai cũng nói Thạnh Mỹ Lợi xa, kẹt xe. Mặt sông Trần Quý Kiên / Trương Văn Bang nay đạt VND 400 triệu/m². Tăng 3-5 lần trong 10 năm.',51),
  ('cb586749-4363-5a46-ae26-719528505670','00000000-0000-0000-0000-00000000a001','thu-duc-master-plan','Masterplan TP Thủ Đức 2040','policy',null,'[{"key":"Duyệt","value":"21/1/2025 — Quyết định 202/QĐ-TTg"},{"key":"Tầm nhìn","value":"2040, định hướng 2050"},{"key":"Gọi vốn","value":"535 dự án ~US$31.6 tỷ"},{"key":"Khu Bình Trưng Tây","value":"Gồm Gladia"}]'::jsonb,null,'Quy hoạch chính thức được Thủ tướng phê duyệt 21/1/2025. 9 phân vùng. Bình Trưng Tây (gồm Gladia) là cầu nối giữa CBD Thủ Thiêm và khu logistic cảng.',52),
  ('70097cf3-8705-59a6-9654-f857b87b61e9','00000000-0000-0000-0000-00000000a001','land-price-list','Bảng giá đất mới 1/1/2026','policy',null,'[{"key":"Hiệu lực","value":"1/1/2026"},{"key":"Tăng","value":"Lên đến 8× bảng giá cũ"}]'::jsonb,null,'Bảng giá đất HCM mới có hiệu lực 1/1/2026, tăng lên đến 8 lần so với bảng cũ. Tác động: tham chiếu thị trường mới, tăng tốc reset giá. Tích cực cho định giá lại; tăng ma sát cho giao dịch 2026.',53),
  ('952992bd-30cf-513a-a154-ce1c2bdf7352','00000000-0000-0000-0000-00000000a001','net-zero','Net-Zero 2050','policy',null,'[{"key":"Cam kết","value":"VN tại COP26"},{"key":"Keppel","value":"Cam kết đồng hành"}]'::jsonb,'"Khi VN net-zero 2050, BĐS không có chứng nhận xanh sẽ mất giá trị. Gladia với BCA Green Mark = chống mất giá tương lai."','Việt Nam đã cam kết net-zero vào 2050 tại COP26. Keppel đã cam kết đồng hành — SHTP đặt mục tiêu net-zero hi-tech park đầu tiên VN vào 2045.',54);
